    b->dados[EFESIOS].capitulos[6].versos[3] = wxT("para que te vá bem, e sejas de longa vida sobre a terra.");
    b->dados[EFESIOS].capitulos[6].versos[4] = wxT("E vós, pais, não provoqueis à ira vossos filhos, mas criai-os na disciplina e admoestação do Senhor.");
    b->dados[EFESIOS].capitulos[6].versos[5] = wxT("Vós, servos, obedecei a vossos senhores segundo a carne, com temor e tremor, na sinceridade de vosso coração, como a Cristo,");
    b->dados[EFESIOS].capitulos[6].versos[6] = wxT("não servindo somente à vista, como para agradar aos homens, mas como servos de Cristo, fazendo de coração a vontade de Deus,");
    b->dados[EFESIOS].capitulos[6].versos[7] = wxT("servindo de boa vontade como ao Senhor, e não como aos homens.");
    b->dados[EFESIOS].capitulos[6].versos[8] = wxT("Sabendo que cada um, seja escravo, seja livre, receberá do Senhor todo bem que fizer.");
    b->dados[EFESIOS].capitulos[6].versos[9] = wxT("E vós, senhores, fazei o mesmo para com eles, deixando as ameaças, sabendo que o Senhor tanto deles como vosso está no céu, e que para com ele não há acepção de pessoas.");
    b->dados[EFESIOS].capitulos[6].versos[10] = wxT("Finalmente, fortalecei-vos no Senhor e na força do seu poder.");
    b->dados[EFESIOS].capitulos[6].versos[11] = wxT("Revesti-vos de toda a armadura de Deus, para poderdes permanecer firmes contra as ciladas do Diabo;");
    b->dados[EFESIOS].capitulos[6].versos[12] = wxT("pois não é contra carne e sangue que temos que lutar, mas sim contra os principados, contra as potestades, conta os príncipes do mundo destas trevas, contra as hostes espirituais da iniqüidade nas regiões celestes.");
    b->dados[EFESIOS].capitulos[6].versos[13] = wxT("Portanto tomai toda a armadura de Deus, para que possais resistir no dia mau e, havendo feito tudo, permanecer firmes.");
    b->dados[EFESIOS].capitulos[6].versos[14] = wxT("Estai, pois, firmes, tendo cingidos os vossos lombos com a verdade, e vestida a couraça da justiça,");
    b->dados[EFESIOS].capitulos[6].versos[15] = wxT("e calçando os pés com a preparação do evangelho da paz,");
    b->dados[EFESIOS].capitulos[6].versos[16] = wxT("tomando, sobretudo, o escudo da fé, com o qual podereis apagar todos os dardos inflamados do Maligno.");
    b->dados[EFESIOS].capitulos[6].versos[17] = wxT("Tomai também o capacete da salvação, e a espada do Espírito, que é a palavra de Deus;");
    b->dados[EFESIOS].capitulos[6].versos[18] = wxT("com toda a oração e súplica orando em todo tempo no Espírito e, para o mesmo fim, vigiando com toda a perseverança e súplica, por todos os santos,");
    b->dados[EFESIOS].capitulos[6].versos[19] = wxT("e por mim, para que me seja dada a palavra, no abrir da minha boca, para, com intrepidez, fazer conhecido o mistério do evangelho,");
    b->dados[EFESIOS].capitulos[6].versos[20] = wxT("pelo qual sou embaixador em cadeias, para que nele eu tenha coragem para falar como devo falar.");
    b->dados[EFESIOS].capitulos[6].versos[21] = wxT("Ora, para que vós também possais saber como estou e o que estou fazendo, Tíquico, irmão amado e fiel ministro no Senhor, vos informará de tudo;");
    b->dados[EFESIOS].capitulos[6].versos[22] = wxT("o qual vos envio para este mesmo fim, para que saibais do nosso estado, e ele vos conforte o coração.");
    b->dados[EFESIOS].capitulos[6].versos[23] = wxT("Paz seja com os irmãos, e amor com fé, da parte de Deus Pai e do Senhor Jesus Cristo.");
